class SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Only allow safe built-in types to prevent arbitrary code execution
        if module == "builtins" and name in ("dict", "list", "tuple", "str", "int", "float", "bool", "NoneType", "set", "frozenset"):
