import base64
import json
import pickle
import io


class RestrictedUnpickler(pickle.Unpickler):
    """Restricted unpickler that only allows safe built-in types."""

    def find_class(self, module, name):
        # Only allow safe built-in types to prevent arbitrary code execution
        allowed_modules = {
            'builtins': {'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool', 'set', 'NoneType'},
            '_builtins': {'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool', 'set', 'NoneType'},
        }

        if module in allowed_modules and name in allowed_modules[module]:
            return super().find_class(module, name)

        # Raise error for any other class to prevent RCE
        raise pickle.UnpicklingError(f"Attempted to unpickle unsafe class {module}.{name}")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Supports both JSON (secure, preferred) and restricted Pickle (legacy) formats.

    Args:
        encoded_prefs: A base64-encoded string containing user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Try JSON first (secure format)
        try:
            preferences = json.loads(decoded_data)
            if isinstance(preferences, dict):
                return preferences
        except (json.JSONDecodeError, UnicodeDecodeError):
            pass

        # Fall back to restricted pickle for backward compatibility
        # This uses a whitelist approach to prevent arbitrary code execution
        try:
            unpickler = RestrictedUnpickler(io.BytesIO(decoded_data))
            preferences = unpickler.load()

            # Validate that the result is a dictionary
            if isinstance(preferences, dict):
                return preferences
        except Exception:
            pass

        return {}

    except (base64.binascii.Error,):
        return {}

