import base64
import logging
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns an empty dict if decoding fails or result is not a dict.
    """
    if not encoded_prefs or not encoded_prefs.strip():
        return {}

    try:
        # Decode the base64 string with strict validation
        decoded_data = base64.b64decode(encoded_prefs, validate=True)

        # Deserialize the preferences object
        preferences = pickle.loads(decoded_data)

        # Validate that the result is actually a dictionary
        if not isinstance(preferences, dict):
            logging.warning("Decoded preferences is not a dictionary")
            return {}

        return preferences

    except (base64.binascii.Error, ValueError) as e:
        # Handle invalid base64 encoding
        logging.warning(f"Invalid base64 encoding in cookie: {e}")
        return {}
    except (pickle.UnpicklingError, EOFError, AttributeError, ImportError, IndexError) as e:
        # Handle pickle deserialization errors and malicious payload attempts
        logging.warning(f"Failed to deserialize preferences: {e}")
        return {}
    except Exception as e:
        # Catch-all for any other unexpected errors during processing
        logging.warning(f"Unexpected error loading preferences: {e}")
        return {}

